/**
 * DOM Validator
 * Validates DOM elements against rules and adds error classes
 */
export default class DOMValidator {
  /**
   * Default error class to add to invalid elements
   */
  static errorClass = 'FlagBugIO-error';
  
  /**
   * Observer for real-time validation
   */
  static observer = null;
  
  /**
   * Map to store validation rules for elements
   */
  static validationRules = new Map();

  /**
   * Initialize real-time validation
   * @param {Object} fieldsConfig - Configuration for fields to validate
   * @returns {Function} - Function to get current validation status
   */
  static initRealTimeValidation(fieldsConfig) {
    // Store validation rules for each element
    for (const selector in fieldsConfig) {
      const config = fieldsConfig[selector];
      const element = document.querySelector(selector);
      
      if (element) {
        // Store the validation rules for this element
        this.validationRules.set(element, {
          rules: config.rules,
          valueType: config.valueType || 'value'
        });
        
        // Add input event listener for real-time validation
        element.addEventListener('input', () => {
          this.validateElement(element, config.rules, config.valueType || 'value');
          this.triggerValidationEvent();
        });
        
        // For contenteditable elements, also validate on blur
        if (element.hasAttribute('contenteditable')) {
          element.addEventListener('blur', () => {
            this.validateElement(element, config.rules, config.valueType || 'value');
            this.triggerValidationEvent();
          });
        }
      }
    }
    
    // Set up observer for dynamically added elements
    this.setupObserver();
    
    // Return a function that can be called to get current validation status
    return () => this.checkAllValidations();
  }
  
  /**
   * Trigger validation status changed event with debouncing
   */
  static debounceTimeout = null;
  static triggerValidationEvent() {
    // Clear any existing timeout
    if (this.debounceTimeout) {
      clearTimeout(this.debounceTimeout);
    }
    
    // Set a new timeout to trigger the event after a short delay
    this.debounceTimeout = setTimeout(() => {
      const event = new CustomEvent('validation-status-changed', { 
        detail: { isValid: this.checkAllValidations() } 
      });
      document.dispatchEvent(event);
    }, 100); // 100ms debounce time
  }
  
  /**
   * Set up MutationObserver to watch for dynamically added elements
   */
  static setupObserver() {
    // Only set up the observer once
    if (this.observer) return;
    
    this.observer = new MutationObserver(mutations => {
      let validationChanged = false;
      
      mutations.forEach(mutation => {
        // Check for attribute changes that might affect validation
        if (mutation.type === 'attributes' && 
            (mutation.attributeName === 'value' || mutation.attributeName === 'data-value')) {
          const element = mutation.target;
          
          // If we have validation rules for this element, validate it
          if (this.validationRules.has(element)) {
            const config = this.validationRules.get(element);
            this.validateElement(element, config.rules, config.valueType);
            validationChanged = true;
          }
        }
        
        if (mutation.addedNodes.length) {
          this.handleAddedNodes(mutation.addedNodes);
          validationChanged = true;
        }
      });
      
      if (validationChanged) {
        this.triggerValidationEvent();
      }
    });
    
    // Start observing the document body for DOM changes
    this.observer.observe(document.body, {
      childList: true,
      subtree: true,
      attributes: true,
      attributeFilter: ['value', 'data-value']
    });
  }
  
  /**
   * Handle nodes added to the DOM
   * @param {NodeList} nodes - Nodes added to the DOM
   */
  static handleAddedNodes(nodes) {
    nodes.forEach(node => {
      // Check if the node is an element
      if (node.nodeType === 1) {
        // Check if we have validation rules for this element
        if (this.validationRules.has(node)) {
          const config = this.validationRules.get(node);
          this.validateElement(node, config.rules, config.valueType);
          this.addValidationListeners(node, config);
        }
        
        // Check for elements within the added node that need validation
        if (node.querySelectorAll) {
          // Use a more specific selector approach instead of trying to match against all rules
          for (const [element, config] of this.validationRules.entries()) {
            // Get a more reliable selector for the element
            const selector = this.getSelectorForElement(element);
            if (selector) {
              const matches = node.querySelectorAll(selector);
              matches.forEach(match => {
                // Verify this is not already being validated
                if (!this.validationRules.has(match)) {
                  this.validationRules.set(match, config);
                  this.validateElement(match, config.rules, config.valueType);
                  this.addValidationListeners(match, config);
                }
              });
            }
          }
        }
      }
    });
  }
  
  /**
   * Add validation event listeners to an element
   * @param {HTMLElement} element - Element to add listeners to
   * @param {Object} config - Validation configuration
   */
  static addValidationListeners(element, config) {
    // Add input event listener for real-time validation
    element.addEventListener('input', () => {
      this.validateElement(element, config.rules, config.valueType);
      this.triggerValidationEvent();
    });
    
    // For contenteditable elements, also validate on blur
    if (element.hasAttribute('contenteditable')) {
      element.addEventListener('blur', () => {
        this.validateElement(element, config.rules, config.valueType);
        this.triggerValidationEvent();
      });
    }
  }
  
  /**
   * Get a CSS selector for an element
   * @param {HTMLElement} element - The element to get a selector for
   * @returns {string} - CSS selector
   */
  static getSelectorForElement(element) {
    if (element.id) {
      return `#${element.id}`;
    } else if (element.className) {
      return `.${element.className.split(' ').join('.')}`;
    } else {
      return element.tagName.toLowerCase();
    }
  }

  /**
   * Validate a single DOM element
   * @param {HTMLElement} element - The DOM element to validate
   * @param {Object} rules - Validation rules
   * @param {string} valueType - Type of value to check ('textContent', 'value', 'innerHTML')
   * @returns {boolean} - Whether validation passed
   */
  static validateElement(element, rules, valueType = 'value') {
    if (!element) {
      console.error('Element not found');
      return false;
    }

    // Get the element's value based on valueType
    let value = this.getElementValue(element, valueType);
    
    let isValid = true;
    const errors = [];

    // Validate against rules
    isValid = this.validateAgainstRules(value, rules, errors);

    // Apply validation UI
    this.applyValidationUI(element, isValid, errors, rules);

    return isValid;
  }
  
  /**
   * Get element value based on valueType
   * @param {HTMLElement} element - The element to get value from
   * @param {string} valueType - Type of value to get
   * @returns {string} - Element value
   */
  static getElementValue(element, valueType) {
    let value = valueType === 'textContent' 
      ? element.textContent 
      : valueType === 'innerHTML' 
        ? element.innerHTML 
        : element.value;
    
    // Check if this is a contenteditable with placeholder and the value equals the placeholder
    if (valueType === 'textContent' && 
        element.hasAttribute('contenteditable') && 
        element.hasAttribute('data-placeholder') &&
        value === element.getAttribute('data-placeholder')) {
      value = ''; // Treat placeholder text as empty value
    }
    
    // For hidden fields, check if there's a data-value attribute
    if (element.type === 'hidden' && element.hasAttribute('data-value')) {
      value = element.getAttribute('data-value');
    }
    
    return value;
  }
  
  /**
   * Validate value against rules
   * @param {string} value - Value to validate
   * @param {Object} rules - Validation rules
   * @param {Array} errors - Array to collect error messages
   * @returns {boolean} - Whether validation passed
   */
  static validateAgainstRules(value, rules, errors) {
    let isValid = true;
    
    // Required check
    if (rules.required && (!value || value.trim() === '')) {
      isValid = false;
      errors.push('This field is required');
    }

    // Min length check
    if (rules.minLength && value.length < rules.minLength) {
      isValid = false;
      errors.push(`Minimum length is ${rules.minLength} characters`);
    }

    // Max length check
    if (rules.maxLength && value.length > rules.maxLength) {
      isValid = false;
      errors.push(`Maximum length is ${rules.maxLength} characters`);
    }

    // Pattern check
    if (rules.pattern && !rules.pattern.test(value)) {
      isValid = false;
      errors.push('Invalid format');
    }

    // Enum check
    if (rules.enum && !rules.enum.includes(value)) {
      isValid = false;
      errors.push(`Value must be one of: ${rules.enum.join(', ')}`);
    }

    // Custom validator function
    if (rules.validator && typeof rules.validator === 'function') {
      const customResult = rules.validator(value);
      if (customResult !== true) {
        isValid = false;
        errors.push(customResult || 'Invalid value');
      }
    }
    
    return isValid;
  }
  
  /**
   * Apply validation UI based on validation result
   * @param {HTMLElement} element - Element to apply UI to
   * @param {boolean} isValid - Whether validation passed
   * @param {Array} errors - Error messages
   * @param {Object} rules - Validation rules
   */
  static applyValidationUI(element, isValid, errors, rules) {
    // Determine the target element (either the element itself or its parent for hidden inputs)
    const targetElement = (element.type === 'hidden' && element.parentElement) 
      ? element.parentElement 
      : element;

    // Store a reference to the element in a data attribute to ensure we're targeting the right element
    targetElement.setAttribute('data-validation-target', 'true');

    // Add or remove error class and message based on validation result
    if (!isValid) {
      // Add error class
      targetElement.classList.add(this.errorClass);
      
      // Add tooltip with error message if specified
      if (rules.showErrorMessage !== false) {
        targetElement.setAttribute('title', errors.join('. '));
        
        // Create or update error message div
        let errorDiv = targetElement.nextElementSibling;
        if (!errorDiv || !errorDiv.classList.contains('FlagBugIO-error-message')) {
          errorDiv = document.createElement('div');
          errorDiv.classList.add('FlagBugIO-error-message');
          // Add a data attribute to link the error message to its target element
          errorDiv.setAttribute('data-error-for', this.getUniqueElementIdentifier(targetElement));
          targetElement.parentNode.insertBefore(errorDiv, targetElement.nextSibling);
        }
        
        errorDiv.textContent = errors.join('. ');
        errorDiv.style.display = 'block';
      }
    } else {
      // Remove error class
      targetElement.classList.remove(this.errorClass);
      targetElement.removeAttribute('title');
      
      // Remove error message div if it exists
      const errorDiv = targetElement.nextElementSibling;
      if (errorDiv && errorDiv.classList.contains('FlagBugIO-error-message') && 
          errorDiv.getAttribute('data-error-for') === this.getUniqueElementIdentifier(targetElement)) {
        errorDiv.style.display = 'none';
      }
    }
  }

  /**
   * Validate multiple form fields
   * @param {Object} fieldsConfig - Configuration for fields to validate
   * @param {boolean} realTime - Whether to enable real-time validation
   * @returns {boolean} - Whether all validations passed
   */
  static validateForm(fieldsConfig, realTime = false) {
    let isFormValid = true;

    // If real-time validation is requested, set it up
    if (realTime) {
      this.initRealTimeValidation(fieldsConfig);
    }

    for (const selector in fieldsConfig) {
      const config = fieldsConfig[selector];
      const element = document.querySelector(selector);
      
      if (!element) {
        console.error(`Element not found: ${selector}`);
        isFormValid = false;
        continue;
      }

      const isFieldValid = this.validateElement(
        element, 
        config.rules, 
        config.valueType || 'value'
      );

      if (!isFieldValid) {
        isFormValid = false;
      }
    }

    return isFormValid;
  }


  /**
   * Reset validation state for a new form
   * This ensures that previous validation errors don't persist to new forms
   */
  static resetValidationState() {
    // Clear any pending debounce
    if (this.debounceTimeout) {
      clearTimeout(this.debounceTimeout);
      this.debounceTimeout = null;
    }
    
    // Reset validation rules map (but keep the observer)
    this.validationRules = new Map();
    
    // Trigger a clean validation event
    const event = new CustomEvent('validation-status-changed', { 
      detail: { isValid: true } 
    });
    document.dispatchEvent(event);
  }

  /**
   * Create and validate a form with default validation rules
   * @param {boolean} realTime - Whether to enable real-time validation
   * @returns {boolean} - Whether all validations passed
   */
  static createFormValidate(realTime = true) {
    // Reset validation state before creating new validation
    if (!realTime) {
      this.resetValidationState();
    }
    
    const defaultFieldsConfig = {
      '.FlagBugIO-form .FlagBugIO-form-title': { rules: { required: true, minLength: 3, maxLength: 100 }, valueType: 'textContent' },
      '.FlagBugIO-form .FlagBugIO-form-description': { rules: { required: true, minLength: 10 }, valueType: 'textContent'},
      '.FlagBugIO-form .FlagBugIO-form-due-date-select input[type="hidden"]': { rules: { required: true } },
      '.FlagBugIO-form .FlagBugIO-form-assignee-select input[type="hidden"]': { rules: { required: true } },
      '.FlagBugIO-form .FlagBugIO-form-priority-select input[type="hidden"]': { rules: { required: true } },
    };
    
    const isValid = this.validateForm(defaultFieldsConfig, realTime);
    return isValid;
  }

  /**
   * Check all current validations
   * @returns {boolean} - Whether all validations are currently passing
   */
  static checkAllValidations() {
    let isAllValid = true;
    
    this.validationRules.forEach((config, element) => {
      // Check if element has error class
      if (element.classList.contains(this.errorClass) || 
          (element.parentElement && element.parentElement.classList.contains(this.errorClass))) {
        isAllValid = false;
      }
    });
    
    return isAllValid;
  }

  /**
   * Generate a unique identifier for an element
   * @param {HTMLElement} element - The element to identify
   * @returns {string} - A unique identifier
   */
  static getUniqueElementIdentifier(element) {
    // Use existing ID if available
    if (element.id) return element.id;
    
    // Generate a unique ID if none exists
    if (!element.hasAttribute('data-validator-id')) {
      const uniqueId = 'validator-' + Math.random().toString(36).substr(2, 9);
      element.setAttribute('data-validator-id', uniqueId);
    }
    
    return element.getAttribute('data-validator-id');
  }

  /**
   * Clear all validation errors
   * @param {string} formSelector - Selector for the form or container
   */
  static clearErrors(formSelector) {
    const container = document.querySelector(formSelector);
    if (!container) return;

    // Find elements with the error class
    const errorElements = container.querySelectorAll(`.${this.errorClass}`);
    errorElements.forEach(element => {
      element.classList.remove(this.errorClass);
      element.removeAttribute('title');
      
      // Find the associated error message using the data attribute
      const elementId = this.getUniqueElementIdentifier(element);
      const errorDiv = container.querySelector(`.FlagBugIO-error-message[data-error-for="${elementId}"]`);
      if (errorDiv) {
        errorDiv.style.display = 'none';
      }
    });
  }

  /**
   * Clean up validation for a specific form or container
   * @param {string} formSelector - Selector for the form or container
   */
  static cleanupValidation(formSelector) {
    const container = document.querySelector(formSelector);
    if (!container) return;
    
    // Clear all validation errors
    this.clearErrors(formSelector);
    
    // Remove validation rules for elements in this container
    const elementsToRemove = [];
    
    this.validationRules.forEach((config, element) => {
      // Check if the element is within the container
      if (container.contains(element)) {
        // Remove event listeners
        element.removeEventListener('input', this.validateElementHandler);
        element.removeEventListener('blur', this.validateElementHandler);
        
        // Add to removal list
        elementsToRemove.push(element);
      }
    });
    
    // Remove elements from validation rules
    elementsToRemove.forEach(element => {
      this.validationRules.delete(element);
    });
    
    // Trigger validation event to update any UI that depends on validation status
    this.triggerValidationEvent();
  }

  /**
   * Cleanup all validation state
   */
  static cleanupAllValidation() {
    // Remove all event listeners
    this.validationRules.forEach((config, element) => {
      element.removeEventListener('input', this.validateElementHandler);
      element.removeEventListener('blur', this.validateElementHandler);
    });
    
    // Clear validation rules
    this.validationRules.clear();
    
    // Stop observer
    if (this.observer) {
      this.observer.disconnect();
      this.observer = null;
    }
    
    // Clear any pending debounce
    if (this.debounceTimeout) {
      clearTimeout(this.debounceTimeout);
      this.debounceTimeout = null;
    }
    
    // Remove all error classes and messages
    const errorElements = document.querySelectorAll(`.${this.errorClass}`);
    errorElements.forEach(element => {
      element.classList.remove(this.errorClass);
      element.removeAttribute('title');
    });
    
    const errorMessages = document.querySelectorAll('.FlagBugIO-error-message');
    errorMessages.forEach(message => {
      message.remove();
    });
  }
}
