/**
 * Format a date relative to now or in absolute format
 * @param {string|Date} dateInput - The date to format (ISO string or Date object)
 * @param {boolean} relative - Whether to show relative time (true) or absolute time (false)
 * @returns {string} - Formatted date string
 */
export function formatDate(dateInput, relative = true) {
    const date = dateInput instanceof Date ? dateInput : new Date(dateInput);
    const now = new Date();
    
    // For absolute format (MMMM DD, HH:MM AM/PM)
    if (!relative) {
      const months = [
        'January', 'February', 'March', 'April', 'May', 'June', 
        'July', 'August', 'September', 'October', 'November', 'December'
      ];
      
      const month = months[date.getMonth()];
      const day = date.getDate();
      let hours = date.getHours();
      const minutes = date.getMinutes().toString().padStart(2, '0');
      const ampm = hours >= 12 ? 'PM' : 'AM';
      
      hours = hours % 12;
      hours = hours ? hours : 12; // Convert 0 to 12
      
      return `${month} ${day}, ${hours}:${minutes} ${ampm}`;
    }
    
    // For relative format
    const diffMs = now - date;
    const diffSec = Math.floor(diffMs / 1000);
    const diffMin = Math.floor(diffSec / 60);
    const diffHour = Math.floor(diffMin / 60);
    const diffDay = Math.floor(diffHour / 24);
    
    if (diffSec < 30) {
      return 'few seconds ago';
    } else if (diffSec < 60) {
      return '30s ago';
    } else if (diffMin < 60) {
      return `${diffMin}m ago`;
    } else if (diffHour < 24) {
      return `${diffHour}h ago`;
    } else {
      return `${diffDay}d ago`;
    }
  }