// Selector helpers to generate full CSS selectors from class names
export const getSelector = (className) => `.${className}`;
export const getIdSelector = (idName) => `#${idName}`;

// Helper to generate compound selectors
export const getNestedSelector = (parentClass, childClass) => 
  `${getSelector(parentClass)} ${getSelector(childClass)}`;
