import Storage from "./src/utils/storage.js";
import Marker from "./src/utils/marker.js";
import apiModel from "./src/model/apiModel.js";
import { STAGE } from "./src/utils/DOMConstants.js";


export default class State {
    constructor( api_endpoint,devMode ) {
        this.devMode = devMode;
        this.stage = null;
        // this.stage = STAGE.INIT;

        this.storage = new Storage();
        this.marker = new Marker(this);
        this.api_endpoint = api_endpoint;


        if(!this.devMode){
            this.role = 'guest';
            this.user = null;
            this.project = null;

            if(this.storage.getItem('user')){
                this.setState('user',this.storage.getItem('user').id);
                this.setState('role',this.storage.getItem('user').role);
                this.setState('stage',STAGE.INIT);
            }else{
                this.setState('user',null);
                this.setState('role','guest');
                this.setState('stage',STAGE.LOGIN);
            }
        }else{
            this.role = 'admin';
            this.user = 1;
            this.project = 1;
        }

        this.api = new apiModel(this);

        this.permissions = {
            "guest":{ "read": false, "write": false, "delete": false },
            "viewer":{ "read": true, "write": false, "delete": false },
            "developer":{ "read": true, "write": true, "delete": true },
            "admin":{ "read": true, "write": true, "delete": true }
        };

        this.teams = [
            { "value": 1, "label": "Pratik", "imageUrl": "https://i.pravatar.cc/30?img=1" },
            { "value": 2, "label": "Vikram", "imageUrl": "https://i.pravatar.cc/30?img=2" },
            { "value": 3, "label": "kamlesh", "imageUrl": "https://i.pravatar.cc/30?img=3" },
            { "value": 4, "label": "Isha", "imageUrl": "https://i.pravatar.cc/30?img=36" },
            { "value": 5, "label": "Hiral", "imageUrl": "https://i.pravatar.cc/30?img=5" },
            { "value": 6, "label": "Saroj", "imageUrl": "https://i.pravatar.cc/30?img=6" },
            { "value": 7, "label": "Hemangi", "imageUrl": "https://i.pravatar.cc/30?img=7" },
            { "value": 8, "label": "Test 123", "imageUrl": "https://i.pravatar.cc/30?img=8" },
            { "value": 9, "label": "Test 456", "imageUrl": "https://i.pravatar.cc/30?img=9" },
        ];

        this.status = [
            { "label": "Open", "value": "open" },
            { "label": "In Progress", "value": "progress" },
            { "label": "Completed", "value": "completed"},
            { "label": "Resolved", "value": "resolved"},
            { "label": "Archived", "value": "archived"}
        ];

        this.priority = [
            { "label": "Low", "value": "low", "imageUrl": "https://placehold.co/30x30/3f51b6/3f51b6" },
            { "label": "Medium", "value": "medium", "imageUrl": "https://placehold.co/30x30/fec901/fec901" },
            { "label": "High", "value": "high", "imageUrl": "https://placehold.co/30x30/ff5723/ff5723" }
        ];


        this.explorer = true;

        this.EnabledTypes = ['inline'];
        this.bug = null;
        this.bugType = 'inline'; // inline , capture
        
        this.bugs = this.storage.getBugs() || [];
        this.overlay = { x: 0, y: 0, width: 0, height: 0, scrollX: 0, scrollY: 0, vh: 0, vw: 0 }
        
        
        this.getProject().then(() => {
            this.loadBugs();
        });
    }

    getState(option) {
        return this[option];
    }

    setState(option, value) {
        if (this.hasOwnProperty(option)) {
            this[option] = value;
            console.log(`State updated: ${option} = ${value}`);
        } else {
            console.warn(`Cannot set undefined property: ${option}`);
        }
    }

    addBug(bug) {
        this.bugs.push(bug);
        this.storage.setItem('bugs', this.bugs);
    }

    updateBug(id, data) {
        const bug = this.bugs.find(bug => bug.id === id);
        if (bug) {
            Object.assign(bug, data);
            this.storage.setItem('bugs', this.bugs);
        }
    }

    async getProject() {
        if(this.devMode){ return; }

        await this.api.getProject().then(data => {
            if(!data){
                return false;
            }else{
                this.user = data.user;
                this.role = data.role;
                this.project = data.project;
                return true;
            }
        }).catch(error => {
            console.error('Error fetching user:', error);
            return false;
        });
    }


    async loadBugs() {
        if(this.devMode){
            this.bugs = this.storage.getBugs() || [];
            this.marker.loadMarker(this.bugs);
            return;
        }

        await this.api.getAllBugs().then(data => {
            this.bugs = data || [];
            this.marker.loadMarker(this.bugs);
            return data;
        });
    }

    isUpdateBug(bug) {
        const existingBug = this.getBugById(bug.id);
        if (!existingBug) return false;


        const keysToCheck = ["assigned_to", "title", "description", "status", "priority", "due_date"];
        let hasChanges = false;
        
        for (const key of keysToCheck) {
            const bugValue = bug[key];
            const existingValue = existingBug[key];
            
            // Handle array comparison (like assigned_to)
            if (Array.isArray(bugValue) && Array.isArray(existingValue)) {
                // If arrays have different lengths or any element is different, values are different
                if (bugValue.length !== existingValue.length || 
                    !bugValue.every((val, idx) => String(val).trim() === String(existingValue[idx]).trim())) {
                    console.log(`[${key}]: Old Value: ${JSON.stringify(existingValue)} New Value: ${JSON.stringify(bugValue)}`);
                    hasChanges = true;
                }
            } 
            // Handle string comparison with trimming
            else if (typeof bugValue === 'string' && typeof existingValue === 'string') {
                if (bugValue.trim() !== existingValue.trim()) {
                    console.log(`[${key}] Old Value: "${existingValue}" New Value: "${bugValue}"`);
                    hasChanges = true;
                }
            }
            // Handle other primitive value comparison
            else if (bugValue !== existingValue) {
                console.log(`Old Value: ${existingValue} New Value: ${bugValue} [${key}]`);
                hasChanges = true;
            }
        }
        
        return hasChanges;
    }

    getBugs() {
        return this.bugs;
    }

    getBugById(id) {
        return this.bugs.find(bug => bug.id === id);
    }


    
}

