import { DOM_CLASSES } from "../utils/DOMConstants.js";

export default class apiModel  {
    constructor(state) {
        this.state = state;
        this.api_endpoint = this.state.api_endpoint;

        this.slug = {
            ALL_BUGS: "tasks/?",
            GET_PROJECT_BY_DOMAIN: "project?domain=",
            ADD_BUG: "tasks/tasks-create",
            UPDATE_BUG: "tasks/edit",
            LOGIN:"user/login"
        }


        

    }


    endPoint( slug, params ) {
        if(!params){ return `${this.api_endpoint}${this.slug[slug]}`; }
        return `${this.api_endpoint}${this.slug[slug]}${params}`;
    }

    async login(username, password) {

        if(this.state.devMode){ 
            this.state.setState('user',6);
            this.state.setState('role','developer');
            this.state.storage.setItem('user',
                {"id":6,"name":"Isha Sinojiya","email":"isha@2cube.studio","role":"developer","profile":"1744969933454-portrait-woman.jpg","token":"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1c2VyX2lkIjo2LCJlbWFpbCI6ImlzaGFAMmN1YmUuc3R1ZGlvIiwiaWF0IjoxNzQ1MzA3MTcyLCJleHAiOjE3NDUzMTA3NzJ9.mhg4KZ-LbV1MePnWaj8FLsnOWHWJ-xYyeoQ6sEn_V98"}
            );
            return true;
        }

        const endpoint = this.endPoint('LOGIN');
        const raw = JSON.stringify({
            "email": username,
            "password": password
        });
        const data = await fetch(endpoint,{
            method: 'POST',
            headers: { 'Content-Type': 'application/json'},
            body: raw
        });
        if(data.ok){
            const response = await data.json();
            this.state.setState('user',response.id);
            this.state.setState('role',response.role);
            this.state.storage.setItem('user',response);
            return true;
        }else{
            return false;
        }

    }

    async getProject() {
        try {
            const endpoint = this.endPoint('GET_PROJECT_BY_DOMAIN',window.location.hostname);
            const response = await fetch(endpoint);
            if (!response.ok) {
                throw new Error('Network response was not ok');
            }
            const data = await response.json();
            if (data.properties.projects) {
                const projects = data.properties.projects;

                const user = {
                    project: projects.project_id
                }

                this.state.setState('project',user.project);
                
                const team = data.properties.member;
                const tempTeam = [];
                team.forEach(member => {
                    if( member.role_in_project === 'viewer' ){ return; }

                    // const imageUrl = member.imageUrl ? `http://192.168.0.159:3030/public/uploads/${member.imageUrl}` : DOM_CLASSES.DEFAULT_THUMB;

                    const imageUrl = member.imageUrl ? DOM_CLASSES.DEFAULT_THUMB : DOM_CLASSES.DEFAULT_THUMB;

                    tempTeam.push({
                        value: member.user_id,
                        label: member.user_name,
                        imageUrl: imageUrl
                    });
                });
                this.state.setState('teams',tempTeam);
            } else {
                console.log('No Project found');
                return null;
            }
        } catch (error) {
            console.error('Error:', error);
            throw error;
        }
    }

    async addBug(bug) {

        if(this.state.devMode){ 
            const bugJson = JSON.parse(bug);
            bugJson.id = new Date().getTime();
            console.log(bugJson);
            this.state.storage.addNewBug(bugJson);
            this.state.addBug(bugJson);
            return true;
        }

        const endpoint = this.endPoint('ADD_BUG');
        const formdata = new FormData();
        formdata.append("payload",bug);

        const data = await fetch(endpoint,{
            method: 'POST',
            body: formdata
        });

        if(data.ok){
            const response = await data.json();
            this.state.storage.addNewBug(response);
            this.state.addBug(response);
            return true;
        }else{
            return false;
        }
        
    }

    async updateBug(bug) {
        
        if(this.state.devMode){ 
            this.state.storage.updateBug(bug.id, bug);
            this.state.updateBug(bug.id, bug);
            return true;
        }

        const endpoint = this.endPoint('UPDATE_BUG');
        const data = await fetch(endpoint,{
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json'},
            body: JSON.stringify(bug)
        });

        if(data.ok){
            const response = await data.json();
            this.state.storage.updateBug(bug.id, response.properties);
            this.state.updateBug(bug.id, response.properties);
            return true;
        }else{
            return false;
        }
        
    }



    async getAllBugs() {
        const endpoint = this.endPoint('ALL_BUGS',`project_id=${this.state.project}`);
        const response = await fetch(endpoint);
        const data = await response.json();
        if(response.status === 401){
            return [];
        }else{
            this.state.storage.setItem('bugs', data.properties);
            return data.properties;
        }
    }
};
