export default class Storage {
    constructor() {
        this.storage = window.localStorage;
    }
    setItem(key, value) {
        if (typeof value === 'object') {
            this.storage.setItem(key, JSON.stringify(value));
        } else {
            this.storage.setItem(key, value);
        }
    }
    
    getItem(key) {
        const item = this.storage.getItem(key);
        try {
            return JSON.parse(item);
        } catch (e) {
            return item;
        }
    }
    removeItem(key) {
        this.storage.removeItem(key);
    }
    clear() {
        this.storage.clear();
    }

    addNewBug(bug) {
        const bugs = this.getItem('bugs') || [];
        bugs.push(bug);
        this.setItem('bugs', bugs);
    }

    updateBug(id, data) {
        console.log('updateBug from storage',id,data);
        const bugs = this.getItem('bugs') || [];
        console.log('updateBug from storage',bugs);
        const bug = bugs.find(bug => bug.id === id);
        if (bug) {
            Object.assign(bug, data);
            this.setItem('bugs', bugs);
        }
    }


    getBugs() {
        return this.getItem('bugs') || [];
    }

    // return total number of bugs
    getBugCount() {
        const bugs = this.getItem('bugs') || [];
        return bugs.length;
    }

    getBugById(id) {
        const bugs = this.getItem('bugs') || [];
        return bugs.find(bug => bug.id === id);
    }

}
