import { InlineController } from './InlineController.js';

import DropdownSelect from '../utils/dropdown.js';
import Tooltip from '../utils/tooltip.js';
import DOMValidator from '../utils/domValidator.js';
import DatePicker from '../utils/date-picker.js';
import FormManager from '../utils/FormManager.js';
import { DOM_CLASSES , STAGE } from '../utils/DOMConstants.js';



export class AppController {
  constructor(state) {
    this.state = state.state;
    this.role = this.state.role;

    console.log('this.state',this.state);

    this.permissions = this.state.permissions[this.role];
    this.currentOpenBugId = null;


    this.availableTypes = {
      inline: new InlineController(this),
      capture: null
    };

    this.formManager = new FormManager();

    //want to add click event in bug-widget-login class
    const LoginButton = document.querySelector('.bug-widget-login');
    if(LoginButton){

      LoginButton.addEventListener('click', () => {
        console.log('login');
        const form = this.formManager.renderLoginForm();

        
      
        form.querySelector('#submit-btn').addEventListener('click', () => {
          const isValid = DOMValidator.validateForm({
            '.login-form-username': { rules: { required: true, minLength: 3, maxLength: 100 }, valueType: 'textContent' },
            '.login-form-password': { rules: { required: true, minLength: 3, maxLength: 100 }, valueType: 'textContent' },
          }, true);
          if (!isValid) {
            console.error('Form validation failed');
            return;
          }


          const username = form.querySelector('.login-form-username').textContent;
          const password = form.querySelector('.login-form-password').textContent;
          console.log(username,password);
          this.state.api.login(username,password).then(data => {
            console.log(data);
            if(data){
              this.formManager.removeLoginForm();
              this.state.setState('stage',STAGE.INIT);
              //window.location.reload();
            }
          });
        });

        form.querySelector('#cancel-btn').addEventListener('click', () => {
          this.formManager.removeLoginForm();
        });
        
      });
    }


    if(this.permissions.read){
      document.addEventListener(DOM_CLASSES.MARKER_EVENT, (e) => {
        if(this.state.stage !== STAGE.INIT && this.state.stage !== STAGE.VIEW_BUG) return;
        // if(this.state.stage !== 'init' && this.state.stage !== 'VIEW_BUG') return;

        const clickedBugId = e.detail.id;
        
        const previousBugId = this.currentOpenBugId;
        this.viewBug(clickedBugId, previousBugId);
        
        this.currentOpenBugId = clickedBugId;
      });
    }
  }

  init() {
    // Use the EnabledTypes directly from state
    if(this.state.stage === STAGE.LOGIN) return;
    this.state.EnabledTypes.forEach(type => {
      if (this.availableTypes[type]) {
        this.availableTypes[type].init();
      }
    });
  }
  
  viewBug(bugId, previousBugId) {
    // Highlight marker
    document.getElementById(`${DOM_CLASSES.MARKER}-${bugId}`).classList.add(DOM_CLASSES.MARKER_ACTIVE);

    const explorerItem = document.querySelector(`.FlagBugMarker-explorer-item[data-bug-id="${bugId}"]`);
    if (explorerItem) {
      explorerItem.classList.add(DOM_CLASSES.MARKER_ITEM_ACTIVE);
    }

    // Handle existing forms
    const existingForms = document.querySelectorAll(`.${DOM_CLASSES.FORM_WRAPPER}`);
    
    if (bugId === previousBugId && existingForms.length > 0) {
      existingForms.forEach(form => this.formManager.removeForm(form, previousBugId));
      this.state.setState('stage', STAGE.INIT);
      return;
    }
    
    if (existingForms.length > 0) {
      existingForms.forEach(form => this.formManager.removeForm(form, previousBugId));
    }
    
    this.state.setState('stage', STAGE.VIEW_BUG);
    
    // Determine form type based on permissions
    let formType = '';
    if (!this.role) return;
    if (!this.permissions.read) return;
    
    formType = this.permissions.write ? 'edit' : 'view';
    
    const bug = this.state.getBugById(bugId);
    if (!bug) return;
    
    // Create and render the form
    const form = this.formManager.renderForm(bug, formType);
    
    // Setup dropdowns and tooltips
    this.bugInfoTooltip(bug);
    this.bugDropdown(form, bug, formType);
    
    // Setup event handlers
    this.setupFormEventHandlers(form, bug, bugId, formType);
    
  }

  setupFormEventHandlers(form, bug, bugId, formType) {
    // Reset validation state before creating new validation
    DOMValidator.resetValidationState();
    
    const isValid = DOMValidator.createFormValidate(true);
    if (!isValid) {
      console.error('Form validation failed');
      return;
    }

    // Cancel button handler
    const cancelBtn = form.querySelector(`#${DOM_CLASSES.CANCEL_BTN}`);
    cancelBtn.addEventListener('click', () => {
      // Clean up validation before removing the form
      DOMValidator.cleanupValidation(`#${form.id}`);
      
      console.log("remove form",form, bugId);
      this.formManager.removeForm(form, bugId);
      this.state.setState('stage', STAGE.INIT);
      this.currentOpenBugId = null;
    });
    
    // If not editable, return early
    if (formType !== 'edit') return;
    
    // Submit button handler for edit mode
    const submitBtn = form.querySelector(`#${DOM_CLASSES.SUBMIT_BTN}`);
    submitBtn.classList.add('disabled');
    
    // Validation handler
    const validationHandler = (event) => {
      const apiJson = this.formManager.getFormData(form, bugId);
      const isUpdateBug = this.state.isUpdateBug(apiJson);
      
      if (event.detail.isValid && isUpdateBug) {
        submitBtn.classList.remove('disabled');
      } else {
        submitBtn.classList.add('disabled');
      }
    };
    
    document.addEventListener('validation-status-changed', validationHandler);
    
    // Cleanup validation listener
    cancelBtn.addEventListener('click', () => {
      document.removeEventListener('validation-status-changed', validationHandler);
    });
    
    // Submit handler
    submitBtn.addEventListener('click', () => {
      const apiJson = this.formManager.getFormData(form, bugId);
      
      this.state.api.updateBug(apiJson).then(data => {
        if (data) {
          // Clean up validation before removing the form
          DOMValidator.cleanupValidation(`#${form.id}`);
          
          this.formManager.removeForm(form, bugId);
          this.state.setState('stage', STAGE.INIT);
          this.currentOpenBugId = null;
        } else {
          console.error('Error saving bug');
          this.state.setState('stage', 'SAVE_BUG_ERROR');
        }
      });
    });
  }

  bugDropdown(form,bug,TYPE) {

      const isClear = false;

      const assigneeDropdown = form.querySelector(`.${DOM_CLASSES.FORM_ASSIGNEE_SELECT}`);
      const statusDropdown = form.querySelector(`.${DOM_CLASSES.FORM_STATUS_SELECT}`);
      const priorityDropdown = form.querySelector(`.${DOM_CLASSES.FORM_PRIORITY_SELECT}`);
      const dueDateDropdown = form.querySelector(`.${DOM_CLASSES.FORM_DUE_DATE_SELECT}`);


      new DropdownSelect({
        element: assigneeDropdown,
        data: this.state.teams,
        type: "single",
        styleType: "avatar",
        placeholder: "Select a team or member",
        permissions: TYPE,
        preselected: [bug.assigned_to],
        searchable: false,
        removeIcon: isClear
    });

    new DropdownSelect({
      element: statusDropdown,
      data: this.state.status,
      type: "single",
      styleType: "avatar",
      placeholder: "Please select a status",
      permissions: TYPE,
      preselected: [bug.status || '' ],
      searchable: false,
      removeIcon: isClear
    });

    // priority dropdown
    new DropdownSelect({
      element: priorityDropdown,
      data: this.state.priority,
      type: "single",
      styleType: "avatar",
      placeholder: "Please select a priority",
      permissions: TYPE,
      preselected: [bug.priority || '' ],
      searchable: false,
      removeIcon: isClear
    });

    new DatePicker({
      element: dueDateDropdown,
      format: 'DD MMMM YYYY',
      selectedDate: bug.due_date || null,
      permissions: TYPE
    });
  }

  bugInfoTooltip(bug) {
    new Tooltip({
      selector: `.${DOM_CLASSES.BUG_INFO}`,
      dataAttributes: true,
      trigger: 'hover',
      interactive: true,
      content: this.formManager.getTooltipTemplate(bug.screeninfo),
      html: true,
      offset: 10
    });
  }

  /**
   * Clean up resources when the application is destroyed
   */
  cleanup() {
    // Clean up all validation
    DOMValidator.cleanupAllValidation();
    
    // Remove event listeners
    document.removeEventListener(DOM_CLASSES.MARKER_EVENT, this.markerEventHandler);
    document.removeEventListener('validation-status-changed', this.validationHandler);
    
    // Clean up other controllers
    Object.values(this.availableTypes).forEach(controller => {
      if (controller && typeof controller.cleanup === 'function') {
        controller.cleanup();
      }
    });
    
    // Clean up form manager
    if (this.formManager) {
      this.formManager.cleanup();
    }
  }
}
