import { DOM_CLASSES } from "./DOMConstants.js";
export default class Marker {
    constructor(state) {
       this.state = state;
    }

    // Add new Marker at position
    addMarker(id, position,index) {
        const marker = document.createElement('div');
        marker.id = `${DOM_CLASSES.MARKER}-${id}`;
        marker.className = `${DOM_CLASSES.MARKER}`;
        marker.style.position = 'absolute';
        marker.style.top = `${position.y}px`;
        marker.style.left = `${position.x}px`;
        marker.textContent = index;
        
        // Add click event listener
        marker.addEventListener('click', () => {
            const event = new CustomEvent(DOM_CLASSES.MARKER_EVENT, { detail: { id } });
            document.dispatchEvent(event);
        });
        
        document.body.appendChild(marker);
    }

    // load Marker
    loadMarker(bugs) {
        bugs.forEach((bug, index) => {
            const position = bug.screeninfo.document;
            this.addMarker(bug.id, position,(index+1));
        });
    }
}
