
import { formatDate } from "./date-formatter.js";
import { DOM_CLASSES, getSelector } from "./DOMConstants.js";
import DOMValidator from "./domValidator.js";

export default class FormManager {
  constructor() {
    this.forms = new Map();
    this.formComponents = new Map(); // Add this line to initialize formComponents
  }

  createForm(viewportInfo, id, type) {
    id = id ? `bug-form-${id}` : `bug-form-${Date.now()}`;
    const form = document.createElement('div');

    form.id = id;
    form.className = `${DOM_CLASSES.FORM_WRAPPER} ${DOM_CLASSES.FADE_IN_EL}`;
    form.style.position = 'absolute';
    form.style.top = `${viewportInfo.y}px`;
    form.style.left = `${viewportInfo.x}px`;

    form.innerHTML = this.getFormTemplate(type);
    
    setTimeout(() => {
      form.classList.add(DOM_CLASSES.FADE_IN);
    }, 100);
    
    this.forms.set(id, form);
    
    // Reset validation state for this new form
    DOMValidator.resetValidationState();
    
    return form;
  }

  getFormTemplate(type) {
    const contenteditable = type === 'create' || type === 'edit' ? true : false;
    
    return `<div class="${DOM_CLASSES.FORM} ${DOM_CLASSES.BORDER} ${DOM_CLASSES.SHADOW}"><div class="${DOM_CLASSES.TITLE_HEADER} ${DOM_CLASSES.FLEX} ${DOM_CLASSES.JUSTIFY_SPACE_BETWEEN}"><div class="${DOM_CLASSES.TITLE_TEXT}"> ${type==='create' ? 'Create New Bug' : type==='edit' ? 'Edit Bug' : 'View Bug'} </div> ${type==='view' || type==='edit' ? this.getFormHeader() : ''} </div><div class="${DOM_CLASSES.FORM_GROUP}"><div class="${DOM_CLASSES.LABEL}">Title</div><div class="${DOM_CLASSES.FORM_TITLE} ${DOM_CLASSES.CONTROL}" data-placeholder="Please enter a title" contenteditable="${contenteditable}"></div></div><div class="${DOM_CLASSES.FORM_GROUP}"><div class="${DOM_CLASSES.LABEL}">Description</div><div class="${DOM_CLASSES.FORM_DESCRIPTION} ${DOM_CLASSES.CONTROL}" contenteditable="${contenteditable}" data-placeholder="Please enter a description"></div></div> ${this.getDueDateField()} <div class="${DOM_CLASSES.ROW} ${DOM_CLASSES.ROW_2}"> ${type==='create' || type==='edit' || type==='view' ? this.getAssigneeField() : ''} ${type==='edit' || type==='create' || type==='view' ? this.getPriorityField() : ''} </div> ${type==='edit' || type==='view' ? this.getStatusField() : ''} ${this.getFormButtons(type)} </div>`;
  }

  getLoginFormTemplate(){
    return `<div class="${DOM_CLASSES.FORM} ${DOM_CLASSES.BORDER} ${DOM_CLASSES.SHADOW}"><div class="${DOM_CLASSES.TITLE_HEADER} ${DOM_CLASSES.FLEX} ${DOM_CLASSES.JUSTIFY_SPACE_BETWEEN}"><div class="${DOM_CLASSES.TITLE_TEXT}">Login</div></div><div class="${DOM_CLASSES.FORM_GROUP}"><div class="${DOM_CLASSES.LABEL}">Username</div><div contenteditable="true" class="${DOM_CLASSES.CONTROL} login-form-username">isha@2cube.studio</div></div><div class="${DOM_CLASSES.FORM_GROUP}"><div class="${DOM_CLASSES.LABEL}">Password</div><div contenteditable="true" class="${DOM_CLASSES.CONTROL} login-form-password">isha@123</div></div> ${this.buttonWrapper()} ${this.submitButton()} ${this.cancleButton()} </div></div>`
  }

  getFormHeader() {
    return `<div class="${DOM_CLASSES.FORM_HEADER} ${DOM_CLASSES.FLEX} ${DOM_CLASSES.FLEX_GAP}"><div class="${DOM_CLASSES.BUG_USER}">pratikchauhancp</div><div class="${DOM_CLASSES.BUG_TIMESTAMP}">3h</div><div class="${DOM_CLASSES.BUG_INFO}"><svg data-testid="geist-icon" fill="none" height="16" shape-rendering="geometricPrecision" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 24 24" width="16" style="color: var(--accents-5);"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"></rect><path d="M8 21h8"></path><path d="M12 17v4"></path></svg></div></div>`;
  }

  getAssigneeField() {
    return `<div class="${DOM_CLASSES.ASSIGNEE} ${DOM_CLASSES.FORM_GROUP}"><div class="${DOM_CLASSES.LABEL}">Assignee</div><div class="${DOM_CLASSES.FORM_ASSIGNEE_SELECT}"></div></div>`;
  }

  getDueDateField() {
    return `<div class="${DOM_CLASSES.FORM_DUE_DATE} ${DOM_CLASSES.FORM_GROUP}"><div class="${DOM_CLASSES.LABEL}">Due Date</div><div class="${DOM_CLASSES.FORM_DUE_DATE_SELECT}"></div></div>`;
  }

  getStatusField() {
    return `<div class="${DOM_CLASSES.STATUS} ${DOM_CLASSES.FORM_GROUP}"><div class="${DOM_CLASSES.LABEL}">Status</div><div class="${DOM_CLASSES.FORM_STATUS_SELECT}"></div></div>`;
  }

  getPriorityField() {
    return `<div class="${DOM_CLASSES.FORM_GROUP} ${DOM_CLASSES.FORM_PRIORITY}"><div class="${DOM_CLASSES.LABEL}">Priority</div><div class="${DOM_CLASSES.FORM_PRIORITY_SELECT}"></div></div>`;
  }

  getFormButtons(type) {
    if (type === 'create') {
      return `
        ${this.buttonWrapper()}
        ${this.submitButton()}
        ${this.cancleButton()}
      </div>`;
    } else if (type === 'view') {
      return `
      ${this.buttonWrapper()}
        ${this.cancleButton()}
      </div>`;
    } else if (type === 'edit') {
      return `
      ${this.buttonWrapper()}
        ${this.submitButton()}
        ${this.cancleButton()}
      </div>`;
    }
    return '';
  }

  buttonWrapper(){
    return `<div class="${DOM_CLASSES.FORM_BUTTONS} ${DOM_CLASSES.FLEX} ${DOM_CLASSES.FLEX_GAP} ">`; } submitButton(){ return `<div class="${DOM_CLASSES.FORM_BUTTON}" id="submit-btn">Submit</div>`;
  }

  cancleButton(){
    return `<div class="${DOM_CLASSES.FORM_BUTTON} ${DOM_CLASSES.FORM_BUTTON_OUTLINE}" id="cancel-btn">Cancel</div>`;
  }

  populateForm(form, bug, type) {
    if (!form || !bug) return;

    form.querySelector(`.${DOM_CLASSES.FORM_TITLE}`).textContent = bug.title || '';
    form.querySelector('.FlagBugIO-form-description').textContent = bug.description || '';
    
    if (type === 'view' || type === 'edit') {
      const timestampEl = form.querySelector('.FlagBugIO-bug-timestamp');
      if (timestampEl && bug.created_at) {
        timestampEl.textContent = formatDate(bug.created_at);
      }
      
      const userEl = form.querySelector('.FlagBugIO-bug-user');
      if (userEl && bug.created_by) {
        userEl.textContent = bug.created_by;
      }
    }
  }

  renderForm(bug, type) {
    const position = bug.screeninfo.document;
    const form = this.createForm(position, bug.id, type);
    this.populateForm(form, bug, type);
    document.body.appendChild(form);
    return form;
  }

  renderLoginForm() {

    const formWrapper = document.createElement('div');
    formWrapper.className = `login-form-wrapper`;
  

    const form = document.createElement('div');
    form.className = `${DOM_CLASSES.FORM_WRAPPER} ${DOM_CLASSES.FADE_IN_EL}`;
    form.innerHTML = this.getLoginFormTemplate();
    formWrapper.appendChild(form);
    document.body.appendChild(formWrapper);

    setTimeout(() => {
      form.classList.add(DOM_CLASSES.FADE_IN);
    }, 100);

    return formWrapper;
  }

  removeLoginForm() {
    const formWrapper = document.querySelector('.login-form-wrapper');
    if (formWrapper) {
      formWrapper.remove();
    }
  }

  /**
   * Remove a form from the DOM
   * @param {HTMLElement} form - The form to remove
   * @param {string} formId - The ID of the bug associated with the form
   */
  removeForm(form, formId = null) {
    if (form) {
      // Clean up component instances if formComponents exists
      if (this.formComponents) {
        const components = this.formComponents.get(form);
        if (components) {
          // Clean up DatePicker
          if (components.datePicker) {
            components.datePicker.cleanup();
          }
          
          // Remove from components map
          this.formComponents.delete(form);
        }
      }
      
      // Clean up validation - use the specific form element to ensure we only clean up this form
      DOMValidator.cleanupValidation(`#${form.id}`);
      
      form.classList.remove(DOM_CLASSES.FADE_IN);
      if (formId) {
        const marker = document.getElementById(`${DOM_CLASSES.MARKER}-${formId}`);
        if (marker) {
          marker.classList.remove(DOM_CLASSES.MARKER_ACTIVE);
        }
        
        const explorerItem = document.querySelector(`.FlagBugMarker-explorer-item[data-bug-id="${formId}"]`);
        if (explorerItem) {
          explorerItem.classList.remove(DOM_CLASSES.MARKER_ITEM_ACTIVE);
        }
      }
      setTimeout(() => {
        form.remove();  
      }, 300);
    }
  }

  getFormData(form, bugId) {
    if (!form) return null;
    
    return {
      id: bugId,
      title: form.querySelector('.FlagBugIO-form-title').textContent,
      description: form.querySelector('.FlagBugIO-form-description').textContent,
      assigned_to: this.getAssigneeArray(form),
      priority: this.getHiddenInputValue(form, '.FlagBugIO-form-priority-select input[type="hidden"]'),
      status: this.getHiddenInputValue(form, '.FlagBugIO-form-status-select input[type="hidden"]'),
      due_date: this.getHiddenInputValue(form, '.FlagBugIO-form-due-date-select input[type="hidden"]')
    };
  }

  getHiddenInputValue(form, selector) {
    const input = form.querySelector(selector);
    return input ? input.value : '';
  }

  getAssigneeArray(form) {
    const selector = `${getSelector(DOM_CLASSES.ASSIGNEE_SELECT)} input[type="hidden"]`;
    const input = form.querySelector(selector);
    if (!input || !input.value) return [];
    
    // Split the comma-separated string and convert each value to an integer
    return input.value.split(',').map(id => parseInt(id.trim(), 10));
  }

  getTooltipTemplate(screeninfo) {
    return `<div class="${DOM_CLASSES.BUG_INFO_CONTAINER}"><div class="${DOM_CLASSES.BUG_INFO_LINE}"><div class="${DOM_CLASSES.BUG_INFO_LABEL}">Browser</div><div class="${DOM_CLASSES.BUG_INFO_VALUE}">${screeninfo.browserInfo.name}</div></div><div class="${DOM_CLASSES.BUG_INFO_LINE}"><div class="${DOM_CLASSES.BUG_INFO_LABEL}">Os</div><div class="${DOM_CLASSES.BUG_INFO_VALUE}">${screeninfo.os.name}</div></div><div class="${DOM_CLASSES.BUG_INFO_LINE}"><div class="${DOM_CLASSES.BUG_INFO_LABEL}">Device</div><div class="${DOM_CLASSES.BUG_INFO_VALUE}">${screeninfo.os.type}</div></div><div class="${DOM_CLASSES.BUG_INFO_LINE}"><div class="${DOM_CLASSES.BUG_INFO_LABEL}">Resolution</div><div class="${DOM_CLASSES.BUG_INFO_VALUE}">${screeninfo.document.width}x${screeninfo.document.height}</div></div></div>`;
  }
}

