import { AppController } from "./src/controller/AppController.js";
import ExplorerController from "./src/controller/ExplorerController.js";
import DatePicker from "./src/utils/date-picker.js";
import Dragable from "./src/utils/dragable.js";
import DropdownSelect from "./src/utils/dropdown.js";
import Tooltip from "./src/utils/tooltip.js";
import ContentEditable from "./src/utils/contenteditable.js";
import State from "./state.js";
import { STAGE } from "./src/utils/DOMConstants.js";


class FlagBugApp{
    constructor() {
        this.api_endpoint = "http://192.168.0.159:3030/api/v1/";
        this.devMode = true;
        this.state = new State(this.api_endpoint,this.devMode);
        this.app = new AppController(this);
        this.app.init();

        if(this.state.stage !== STAGE.LOGIN){
            new Dragable(document.getElementById('widgetOptionPicker'));
        }
        this.explorer = new ExplorerController(this);
        ContentEditable.initAll();
    }
}

window.FlagBugApp = FlagBugApp;